var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 부르자, 약속한 장소에서 기다리고 있겠다는 대답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_SPECIAL_ON","text":{"KOREA":"드디어… 둘만 있게 되었네요. 사장님.","JPN":"いよいよ……二人きりになりましたね。社長。","ENG":"Finally... We're all alone, Boss.","TWN":"老闆，終於…只剩下你和我。"},"stage":{"bg":"JIA_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_SPECIAL_ON","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_SPECIAL_ON","text":{"KOREA":"어떤가요, 이렇게 아득히 높은 곳에서 부감하는 풍경… 꽤나 나쁘지 않죠?","JPN":"どうですか？　こんな果てしなく高いところから見下ろす風景……なかなか悪くないでしょう？","ENG":"So? How does it feel to overlook the world from all the way up here? Not bad, right?","TWN":"怎麼樣？從高處俯瞰的風景…很不錯吧？"},"stage":{"bg":"JIA_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_SPECIAL_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_SPECIAL_ON","text":{"KOREA":"여기서 내려다보고 있으면, 저 작게 보이는 사람들의 풍경과 여기 있는 저의 풍경이 다르다는 걸 분명히 느끼거든요.","JPN":"ここから見下ろしていると、あの小さく見える人たちの風景とここにいる私の風景が違うということをはっきりと感じるんです。","ENG":"When I look down, I can clearly see that what I see from up here differs greatly from what the people down there see.","TWN":"從這裡往下看就可以明顯感受到，底下那些渺小的人看到的景色，和我看到的景色是全然不同的。"},"stage":{"bg":"JIA_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_SPECIAL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_SPECIAL_ON","text":{"KOREA":"다시 말하면, 이곳의 풍경을 공유하고 있는 사람은 오로지 사장님과 저 둘뿐이라는 거죠.","JPN":"言い換えますと、この風景を共有している人はただ社長と私、二人きりってことです。","ENG":"In other words, the only person whom I can share this scenery with is you, Boss.","TWN":"我要再次強調，這裡的景色我只跟老闆分享，是專屬於我們的。"},"stage":{"bg":"JIA_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_SPECIAL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_SPECIAL_ON","text":{"KOREA":"물론, 지금 사장님의 관심사는 야경 같은 게 아니라… 사장님만을 위해 특별히 준비한 이 모습이겠지만요.","JPN":"もちろん、今社長が興味を持っているものは夜景なんかではなくて……社長のためだけに特別に準備したこの姿でしょうけど。","ENG":"Of course, I know you're more interested in this special Jia than the night scenery.","TWN":"不過我知道，老闆現在關心的不是這個夜景…而是我特地為老闆準備的這身裝扮。"},"stage":{"bg":"JIA_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_SPECIAL_ON","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_SPECIAL_ON","text":{"KOREA":"…후후훗, 귀여우셔라.","JPN":"……ふふふっ、可愛らしい。","ENG":"Fuu fuu fuu, how cute.","TWN":"…呵呵呵，真可愛。"},"stage":{"bg":"JIA_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_SPECIAL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_SPECIAL_ON","text":{"KOREA":"지아는 사장님이 원하는 거라면 뭐든 알고 있는 걸요.","JPN":"ユイは社長が望むことなら何でも知ってますから。","ENG":"Jia knows everything you want, Boss.","TWN":"老闆內心所想的我全都知道。"},"stage":{"bg":"JIA_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_SPECIAL_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_SPECIAL_ON","text":{"KOREA":"왜냐하면… 사장님은 이 세계에서 단 한 명뿐인 저의 이해자니까.","JPN":"だって……社長はこの世界にたった一人の私の理解者ですから。","ENG":"Because... you're the only one who truly understands me.","TWN":"因為…老闆是在這個世界上，唯一懂我的人。"},"stage":{"bg":"JIA_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_SPECIAL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_SPECIAL_ON","text":{"KOREA":"<color=#ffd34c>있는 그대로의 저</color>를… 평범한 인간으로서 저를 봐주실 수 있는 유일한 분이니까요.","JPN":"<color=#ffd34c>ありのままの私</color>を……普通の人間として見てくださる唯一の方ですから。","ENG":"You are the only person who sees me for... <color=#ffd34c>who I really am</color>.","TWN":"你是唯一一個，可以將<color=#ffd34c>我本來的樣子</color>…視為普通人的人。"},"stage":{"bg":"JIA_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_SPECIAL_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_SPECIAL_ON","text":{"KOREA":"그러니까 한눈 팔지 말고 저만 바라봐 주세요.","JPN":"ですからよそ見しないで私だけを見てください。","ENG":"So I want you to keep your eyes only on me.","TWN":"所以眼睛只看著我，不要分心。"},"stage":{"bg":"JIA_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_SPECIAL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_SPECIAL_ON","text":{"KOREA":"그리고 뭐든 말씀만 해주세요. 사장님께서 바라산다면 그게 무엇이든……","JPN":"そして何でも言ってください。社長がお望みならそれが何であっても……","ENG":"Also, feel free to ask me anything. Whatever you want I'll...","TWN":"將你的一切告訴我，無論老闆的願望是什麼，我都……"},"stage":{"bg":"JIA_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_SPECIAL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_SPECIAL_ON","text":{"KOREA":"……네? 그럼 안아 달라고요?","JPN":"……はい？　それじゃあ抱きしめてほしい？","ENG":"H-huh? You want me to hug you?","TWN":"……什麼？抱抱你嗎？"},"stage":{"bg":"JIA_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_SPECIAL_ON","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_SPECIAL_ON","text":{"KOREA":"정말로 그게 끝인가요?","JPN":"本当にそれだけですか？","ENG":"Is that really all you want?","TWN":"真的這樣就好嗎？"},"stage":{"bg":"JIA_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_SPECIAL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_SPECIAL_ON","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"JIA_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_SPECIAL_ON","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_SPECIAL_ON","text":{"KOREA":"후후, 역시 사장님은 재밌는 분이시네요. 자, 얼마든지 제 품에 안기세요. 사장님.","JPN":"ふふ、やはり社長は面白い方ですね。さあ、いくらでもどうぞ。","ENG":"Fu fu. You really are funny. All right. You're welcome into my arms anytime, Boss.","TWN":"呵呵，老闆果然很有意思。來吧，儘管到我懷裡來，老闆。"},"stage":{"bg":"JIA_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_SPECIAL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_SPECIAL_ON","text":{"KOREA":"아아, 따뜻해라. 이래서는 마치 제가 사장님 품에 안긴 것 같은 느낌인데요.","JPN":"ああ、暖かい。これではまるで私が社長に抱きしめられているような感じですけどね。","ENG":"Aah... It's so warm. It feels as if you're hugging me.","TWN":"啊～好溫暖，感覺好像我在老闆懷裡一樣。"},"stage":{"bg":"JIA_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_SPECIAL_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_SPECIAL_ON","text":{"KOREA":"행복해요, 사장님. 조금만… 조금만 더 이대로 응석을 부려도 될까요?","JPN":"幸せです、社長。もう少し……もう少しだけこのまま甘えてもいいですか？","ENG":"I'm so happy. Could we... Could we stay like this for a little longer?","TWN":"好幸福。老闆，可以…讓我再耍賴一下嗎？"},"stage":{"bg":"JIA_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_SPECIAL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_SPECIAL_ON","text":{"KOREA":"기억하고 싶지 않은 일들… 아픈 일들… 다 날아갈 때까지.","JPN":"覚えていたくないこと……苦しいこと……すべてが飛んでいくまで。","ENG":"Just until... All the bad memories... and pain... fade away?","TWN":"直到我不願想起的事…痛苦的事…全都消散為止。"},"stage":{"bg":"JIA_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_SPECIAL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JIA_ALPHA_NEXT_SPECIAL_ON","text":{"KOREA":"제가 저로 남아있을 때까지.","JPN":"私が私でいられるまで。","ENG":"Until only I remain.","TWN":"直到我可以做我自己為止。"},"stage":{"bg":"JIA_SPECIAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NEXT_SPECIAL_ON","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};